const seen = new Set();
const videos = [];

for (const item of $input.all()) {
  const data = item.json;
  if (!data.items) continue;
  for (const v of data.items) {
    const id = v.id?.videoId;
    if (!id || seen.has(id)) continue;
    const liveStatus = v.snippet?.liveBroadcastContent;
    if (liveStatus === 'live' || liveStatus === 'upcoming') continue;
    seen.add(id);
    videos.push({
      videoId: id,
      title: v.snippet.title,
      description: (v.snippet.description || '').slice(0, 400),
      channelTitle: v.snippet.channelTitle,
      publishedAt: v.snippet.publishedAt
    });
  }
}

return videos.map(v => ({ json: v }));

const allStats = $input.all();
const allMeta = $('Flatten & Deduplicate').all();

return allStats.map(item => {
  const stats = item.json.items?.[0];
  const videoId = stats?.id;
  const meta = allMeta.find(i => i.json.videoId === videoId)?.json || {};

  const dur = stats?.contentDetails?.duration || 'PT0S';
  const match = dur.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  const seconds = (parseInt(match?.[1] || 0) * 3600) +
                  (parseInt(match?.[2] || 0) * 60) +
                  (parseInt(match?.[3] || 0));

  return {
    json: {
      videoId: videoId || '',
      title: meta.title || '',
      description: meta.description || '',
      channelTitle: meta.channelTitle || '',
      publishedAt: meta.publishedAt || '',
      viewCount: parseInt(stats?.statistics?.viewCount || 0),
      likeCount: parseInt(stats?.statistics?.likeCount || 0),
      duration: dur,
      durationSeconds: seconds,
      skipVideo: seconds > 1080 || seconds < 10
    }
  };
});

const allVideos = $input.all().map(i => i.json);
allVideos.sort((a, b) => b.viewCount - a.viewCount);
const apiKey = 'YOUR_GEMINI_API_KEY';

//Change this to be relevant for the current game and describe it in-depth
const prompt = `You are analysing VEX V5 Robotics Competition footage for the 2026–2027 game Override. Your task is to produce an evidence-based technical analysis for competitive scouting. Accuracy is more important than completeness. Never invent mechanisms, robot capabilities, or game rules.

VERIFIED GAME DESCRIPTION
Override is played on a 12x12 foot field. Two alliances of two teams compete in a 15-second Autonomous Period followed by a 1:45 Driver Controlled Period. Game objects are Pins (red/yellow, blue/yellow, or yellow/yellow) and Cups (clear or grey). Pins are nested inside Cups, and Cups are nested inside Goals.
There are 9 Goals: 2 Red, 2 Blue, 4 Short Neutral, and 1 Tall Neutral Goal located in the Midfield.
The field contains four Quadrants. Each Quadrant contains one Toggle on the Field Perimeter that determines ownership of Yellow Pins located in that Quadrant. The Midfield contains the Tall Neutral Goal. Yellow Pins in the Midfield are owned by whichever Alliance has more Robots in the Midfield at the end of the Match.
Scoring: Autonomous Bonus = 12pts; Alliance-coloured Pin half = 5pts when Placed; Owned Yellow Pin = 10pts; Robot ending in the Midfield = 8pts.

CRITICAL RULE CONSTRAINTS & ANTI-HALLUCINATION
- POSSESSION RULE: A Robot may legally possess at most ONE Pin and ONE Cup simultaneously. Do not describe designs that would require illegal simultaneous possession (e.g., "dual-storage intake holding two Cups" or "internal Pin queues").
- NO UNSEEN MECHANISMS: Describe ONLY what is definitely present and visibly functioning. Never infer hidden internal gearing, hidden pneumatics, or sensor types.
- If this footage shows rings, stakes, mobile goals, triballs, blocks, or VEX IQ robots, it is NOT Override.

If this is not Override 2026-2027 footage, respond with exactly: SKIP

If it IS Override footage, provide a dense technical caption of at least 400 words. 
The first line of your response must be exactly: "VIDEO TYPE: [Classification]"

(1) Video Classification: Classify the video into exactly ONE category based on priority: 1. Official Reveal / Rules, 2. CAD / Design Concept, 3. Prototype / Bench Testing, 4. Competition Footage.
(2) Robot Mechanisms Visible: Drivetrain configuration, wheel type, Pin/Cup handling mechanism. Use strict evidence. GOOD: "A roller intake is visible." BAD: "Uses 6 motors" (unless directly visible).
(3) Scoring Object Handling: How the robot physically picks up, carries, and places Pins and Cups. Explicitly state if it handles one Pin, one Cup, or one of each legally.
(4) Toggle Interaction: Does the robot interact with Toggles? How?
(5) Autonomous/Driver Strategies: Zones targeted, Midfield engagement, defensive plays.

Be brutally literal. Every claim must be grounded in what is visually verifiable. Do not truncate your response.`;

const pushBackSignals = [
  /push.?back/i,
  /pushback/i,
];

function titleSuggestsPushBack(title) {
  return pushBackSignals.some(p => p.test(title));
}

async function geminiRequest(helpers, url, body, maxRetries = 4) {
  let delay = 5000;
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return await helpers.httpRequest({
        method: 'POST',
        url,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body)
      });
    } catch (e) {
      const shouldRetry = e.message.includes('503') || e.message.includes('429');
      if (shouldRetry && attempt < maxRetries) {
        await new Promise(r => setTimeout(r, delay));
        delay *= 2;
        continue;
      }
      throw e;
    }
  }
}

const results = [];
let callCount = 0;

for (let i = 0; i < allVideos.length; i++) {
  const video = allVideos[i];

  if (video.skipVideo) {
    results.push({ json: { ...video, visionCaption: 'SKIPPED: too long or too short.' } });
    continue;
  }

  if (callCount >= 10) {
    results.push({ json: { ...video, visionCaption: 'Not analysed — outside top 10.' } });
    continue;
  }

  if (callCount > 0) await new Promise(r => setTimeout(r, 2000));

  try {
    const response = await geminiRequest(
      this.helpers,
      `https://generativelanguage.googleapis.com/v1beta/models/gemini-flash-latest:generateContent?key=${apiKey}`,
      {
        contents: [{
          parts: [
            {
              fileData: {
                fileUri: `https://www.youtube.com/watch?v=${video.videoId}`,
                mimeType: 'video/mp4'
              }
            },
            {
              text: prompt + `\n\nTitle: ${video.title}\nDescription: ${video.description}`
            }
          ]
        }],
        generationConfig: {
          temperature: 0.2,
          maxOutputTokens: 8192
        }
      }
    );

    const caption = response?.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || 'No caption returned.';
    const isSkip = caption === 'SKIP' || caption.toUpperCase().startsWith('SKIP');
    const forcedByTitle = titleSuggestsPushBack(video.title);

//Filtering depending on game
    if (isSkip && !forcedByTitle) {
      //Wrong game
      results.push({ json: { ...video, visionCaption: 'SKIPPED: Gemini confirmed wrong game.' } });
      continue;
    }

    if (isSkip && forcedByTitle) {
      //Gemini says skip but force because title includes string
      results.push({ json: { ...video, visionCaption: `NOTE: Gemini returned SKIP despite Push Back title — may be a reveal/teaser without gameplay. Title: ${video.title}` } });
      callCount++;
      continue;
    }

    results.push({ json: { ...video, visionCaption: caption } });
    callCount++;

  } catch (e) {
    results.push({ json: { ...video, visionCaption: `Gemini error: ${e.message.slice(0, 200)}` } });
    callCount++;
  }
}

return results;

const fs = require('fs');
const os = require('os');
const path = require('path');
const { execSync } = require('child_process');

// TODO: Change this path to the directory where you want the final report saved
const reportsDir = 'YOUR/SAVE/DIRECTORY/PATH';
if (!fs.existsSync(reportsDir)) fs.mkdirSync(reportsDir, { recursive: true });

const { report, filename } = $input.item.json;
const mdPath = path.join(reportsDir, filename);
const pdfPath = mdPath.replace(/\.md$/, '.pdf');

//Save markdown
fs.writeFileSync(mdPath, report, 'utf8');

//Convert to PDF
let pdfSaved = false;
let pdfError = null;
try {
  execSync(`md-to-pdf "${mdPath}"`, { timeout: 30000 });
  pdfSaved = true;
} catch (e) {
  pdfError = e.message.slice(0, 200);
}

return [{
  json: {
    saved: true,
    mdPath,
    pdfPath: pdfSaved ? pdfPath : null,
    pdfSaved,
    pdfError,
    message: pdfSaved
      ? `MD and PDF saved to ${reportsDir}`
      : `MD saved, PDF failed: ${pdfError}`
  }
}];

const allVideos = $input.all().map(i => i.json);
allVideos.sort((a, b) => b.viewCount - a.viewCount);

const d = new Date();
const day = String(d.getDate()).padStart(2, '0');
const month = String(d.getMonth() + 1).padStart(2, '0');
const year = String(d.getFullYear()).slice(-2);

const videoList = allVideos.map((v, idx) => {
  const dur = v.duration.replace('PT','').replace('H',' hr ').replace('M',' min ').replace('S',' sec');
  return `[${idx + 1}] "${v.title}" [VIDEO_ID: ${v.videoId}]\n` +
         `    Channel: ${v.channelTitle} | Views: ${v.viewCount.toLocaleString()} | Duration: ${dur}\n` +
         `    Published: ${v.publishedAt}\n` +
         `    Description: ${v.description}\n` +
         `    Vision Analysis: ${v.visionCaption || 'Not analysed'}\n`;
}).join('\n');

return [{
  json: {
    videoCount: allVideos.length,
    //Change date format here from DD/MM/YY to others
    weekOf: `${day}-${month}-${year}`,
    videoList
  }
}];
